remarks.code:
 try
 {
     argumentService.CreateArgument(args);
 }
 catch (ArgumentException ex)
 {
     // Retrieve the error code using the standard key
     var errorCode = ex.Data[ErrorConstants.ErrorCode]?.ToString();

     // Handle specific errors using exception filters
     if (errorCode == ArgumentServiceErrors.DuplicateName)
     {
         // Handle duplicate name scenario
     }
 }

try
{
    var argument = argumentService.CreateArgument(args);
}
catch (Exception ex)
{
    var errorCode = ex.Data[ErrorConstants.ErrorCode]?.ToString();
    Console.WriteLine($"Operation failed with error code: {errorCode}");
}

try
{
    argumentService.CreateArgument(args);
}
catch (ArgumentException ex) when (ex.Data["ErrorCode"]?.ToString() == ArgumentServiceErrors.OnlyInArgumentsSupported)
{
    // Handle: Expression provided for Out/InOut argument
}
catch (InvalidOperationException ex) when (ex.Data["ErrorCode"]?.ToString() == ArgumentServiceErrors.NoActiveDesigner)
{
    // Handle: No active designer available
}

example.code:
 // Integer literal
 argumentService.SetDefaultValue(intArg, "42");

 // String literal (must be quoted)
 argumentService.SetDefaultValue(stringArg, "\"hello world\"");

 // Expression
 argumentService.SetDefaultValue(dateArg, "DateTime.Now");

