example.code:
 // Integer argument with literal default
 new CreateArgumentArgs { Name = "count", Type = typeof(int), Direction = ArgumentDirection.In, Expression = "42" }

 // String argument with literal default (note the escaped quotes)
 new CreateArgumentArgs { Name = "message", Type = typeof(string), Direction = ArgumentDirection.In, Expression = "\"hello\"" }

 // Expression default
 new CreateArgumentArgs { Name = "now", Type = typeof(DateTime), Direction = ArgumentDirection.In, Expression = "DateTime.Now" }

 // Out argument (Expression must be null)
 new CreateArgumentArgs { Name = "result", Type = typeof(string), Direction = ArgumentDirection.Out }
